const items = $input.all();
const tickerItem = items.find(i => i.json && (i.json.symbol === 'BTCUSDT' || (Array.isArray(i.json) && i.json.some(x => x.symbol === 'BTCUSDT'))));
const calendarItem = items.find(i => i.json && (i.json.economicCalendar || (Array.isArray(i.json) && i.json.length && i.json[0].event)));
let tickers = [];
if (Array.isArray(tickerItem?.json)) tickers = tickerItem.json.filter(t => ['BTCUSDT','ETHUSDT'].includes(t.symbol));
else if (tickerItem?.json?.symbol) tickers = [tickerItem.json];
let events = [];
if (calendarItem?.json?.economicCalendar) events = calendarItem.json.economicCalendar;
else if (Array.isArray(calendarItem?.json)) events = calendarItem.json;
const highEvents = events.filter(e => (e.impact && e.impact.toLowerCase() === 'high') || (e.importance >= 2)).slice(0, 8);
const payload = {
  tickers: tickers.map(t => ({ symbol: t.symbol, lastPrice: t.lastPrice, priceChangePercent: t.priceChangePercent, volume: t.volume })),
  upcomingEvents: highEvents.map(e => ({ time: e.time, country: e.country, event: e.event || e.title })),
  generatedAt: new Date().toISOString()
};
return [{ json: payload }];

