const ai = $input.first().json;
const choice = ai.choices && ai.choices[0];
const content = (choice && choice.message && choice.message.content) ? choice.message.content : 'No digest.';
const text = `📬 *Trading Signals Digest*\n\n${content}`;
return [{ json: { text, parse_mode: 'Markdown' } }];
